{
  "resolution_strategies": [
    {
      "resolution_strategy_id": "RS1_insert_email_after_credit_check_and_parallelize",
      "change_operations": [
        {
          "operation": "insert_after",
          "parameters": {
            "target_activity_label": "Check Credit Worthiness",
            "new_activity_label": "send automated email"
          }
        },
        {
