        {
          "operation": "insert_before",
          "parameters": {
            "target_activity_label": "Check Credit Worthiness",
            "new_activity_label": "send automated email"
          }
        },
        {
          "operation": "parallelize",
          "parameters": {
            "first_activity_label": "send automated email",
            "second_activity_label": "Check Credit Worthiness"
